# setup_server.ps1 - Genera la carpeta Server/ con todos los archivos del chat GCP
Write-Host ""
Write-Host "  Generando carpeta Server del Chat GCP..." -ForegroundColor Cyan
Write-Host ""

# Crear carpetas
$root = Split-Path -Parent $MyInvocation.MyCommand.Path
New-Item -ItemType Directory -Force -Path "$root\Server" | Out-Null
New-Item -ItemType Directory -Force -Path "$root\Server\Models" | Out-Null
New-Item -ItemType Directory -Force -Path "$root\Server\Database" | Out-Null
New-Item -ItemType Directory -Force -Path "$root\Server\Handlers" | Out-Null

# Escribir archivos
[System.IO.File]::WriteAllBytes("$root\Server\Program.cs", [System.Convert]::FromBase64String(""))
Write-Host "  OK  Server\Program.cs" -ForegroundColor Green
[System.IO.File]::WriteAllBytes("$root\Server\Models\ChatMessage.cs", [System.Convert]::FromBase64String(""))
Write-Host "  OK  Server\Models\ChatMessage.cs" -ForegroundColor Green
[System.IO.File]::WriteAllBytes("$root\Server\Models\ByteBufferPool.cs", [System.Convert]::FromBase64String(""))
Write-Host "  OK  Server\Models\ByteBufferPool.cs" -ForegroundColor Green
[System.IO.File]::WriteAllBytes("$root\Server\Models\ChatRoom.cs", [System.Convert]::FromBase64String(""))
Write-Host "  OK  Server\Models\ChatRoom.cs" -ForegroundColor Green
[System.IO.File]::WriteAllBytes("$root\Server\Database\ChatDatabase.cs", [System.Convert]::FromBase64String(""))
Write-Host "  OK  Server\Database\ChatDatabase.cs" -ForegroundColor Green
[System.IO.File]::WriteAllBytes("$root\Server\Handlers\TcpClientHandler.cs", [System.Convert]::FromBase64String(""))
Write-Host "  OK  Server\Handlers\TcpClientHandler.cs" -ForegroundColor Green
[System.IO.File]::WriteAllBytes("$root\Server\Handlers\UdpServerHandler.cs", [System.Convert]::FromBase64String(""))
Write-Host "  OK  Server\Handlers\UdpServerHandler.cs" -ForegroundColor Green
[System.IO.File]::WriteAllBytes("$root\Server\Handlers\RestApiHandler.cs", [System.Convert]::FromBase64String(""))
Write-Host "  OK  Server\Handlers\RestApiHandler.cs" -ForegroundColor Green
[System.IO.File]::WriteAllBytes("$root\Server\ChatServer.csproj", [System.Convert]::FromBase64String(""))
Write-Host "  OK  Server\ChatServer.csproj" -ForegroundColor Green

Write-Host ""
Write-Host "============================================" -ForegroundColor Yellow
Write-Host " LISTO! Carpeta Server/ generada." -ForegroundColor Yellow
Write-Host "============================================" -ForegroundColor Yellow
Write-Host ""
Write-Host "Siguiente paso en Git Bash:" -ForegroundColor Cyan
Write-Host "  gcloud compute scp --recurse ./Server/ chat-server:~/chat-server/ --zone=us-central1-a" -ForegroundColor White
Write-Host ""
Read-Host "Presiona Enter para cerrar"